diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 2d7524e8018b..43fdf39bfd80 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1266,9 +1266,86 @@ Value *InstCombinerImpl::foldEqOfParts(Value *Cmp0, Value *Cmp1, bool IsAnd) {
   return Builder.CreateICmp(Pred, LValue, RValue);
 }

-/// Reduce logic-of-compares with equality to a constant by substituting a
-/// common operand with the constant. Callers are expected to call this with
-/// Cmp0/Cmp1 switched to handle logic op commutativity.
+/// Fold (icmp ult/ule X, C1) & (icmp eq (and X, C2), C3)
+/// into (icmp eq (and X, C2), C3) when the masked equality implies the range.
+/// For example:
+///   (icmp ult i8 %a, 5) & (icmp eq i8 (and i8 %a, -2), 2)
+/// The masked equality means %a is in {2, 3}, both of which are < 5,
+/// so the range check is redundant.
+static Value *foldAndOfICmpRangeAndMaskedEq(ICmpInst *CmpRange, ICmpInst *CmpMask,
+                                            bool IsAnd, bool IsLogical,
+                                            InstCombiner::BuilderTy &Builder) {
+  // Only handle AND case (not OR).
+  if (!IsAnd)
+    return nullptr;
+
+  // CmpRange must be an unsigned less-than comparison with a constant.
+  CmpPredicate RangePred;
+  Value *X;
+  const APInt *RangeC;
+  if (!match(CmpRange, m_ICmp(RangePred, m_Value(X), m_APInt(RangeC))))
+    return nullptr;
+
+  // We need ult or ule.
+  if (RangePred != ICmpInst::ICMP_ULT && RangePred != ICmpInst::ICMP_ULE)
+    return nullptr;
+
+  // CmpMask must be an equality comparison with (and X, MaskC) == MaskVal.
+  CmpPredicate MaskPred;
+  Value *AndOp, *MaskVal;
+  const APInt *MaskC;
+  if (!match(CmpMask, m_ICmp(MaskPred, m_And(m_Specific(X), m_APInt(MaskC)),
+                            m_Value(MaskVal))) &&
+      !match(CmpMask, m_ICmp(MaskPred, m_Value(MaskVal),
+                            m_And(m_Specific(X), m_APInt(MaskC)))))
+    return nullptr;
+
+  // Mask must be equality.
+  if (MaskPred != ICmpInst::ICMP_EQ)
+    return nullptr;
+
+  const APInt *MaskValC;
+  if (!match(MaskVal, m_APInt(MaskValC)))
+    return nullptr;
+
+  // The mask check (X & MaskC) == MaskValC implies X is in a specific set.
+  // For (X & MaskC) == MaskValC to be valid, we need (MaskValC & ~MaskC) == 0.
+  if ((*MaskValC & ~*MaskC) != 0)
+    return nullptr;
+
+  // Compute the set of values that satisfy (X & MaskC) == MaskValC.
+  // These are values where all bits in MaskC are fixed to MaskValC,
+  // and the remaining bits are free.
+  // The minimum value is MaskValC (with all free bits 0).
+  // The maximum value is MaskValC | ~MaskC (with all free bits 1).
+  APInt MinVal = *MaskValC;
+  APInt MaxVal = *MaskValC | ~*MaskC;
+
+  // Check if all values in [MinVal, MaxVal] satisfy the range check.
+  // For ult: all values must be < RangeC.
+  // For ule: all values must be <= RangeC.
+  bool Implied = false;
+  if (RangePred == ICmpInst::ICMP_ULT) {
+    // All values in the masked set must be < RangeC.
+    // This is true if MaxVal < RangeC.
+    Implied = MaxVal.ult(*RangeC);
+  } else { // ICMP_ULE
+    // All values in the masked set must be <= RangeC.
+    // This is true if MaxVal <= RangeC.
+    Implied = MaxVal.ule(*RangeC);
+  }
+
+  if (!Implied)
+    return nullptr;
+
+  // The range check is redundant. Return the mask check.
+  // For logical and, we need to handle poison safety.
+  if (IsLogical && !isGuaranteedNotToBeUndefOrPoison(CmpMask))
+    return nullptr;
+
+  return CmpMask;
+}
+
 static Value *foldAndOrOfICmpsWithConstEq(ICmpInst *Cmp0, ICmpInst *Cmp1,
                                           bool IsAnd, bool IsLogical,
                                           InstCombiner::BuilderTy &Builder,
@@ -3423,8 +3500,14 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
     return V;
   }

-  if (Value *V = foldIsPowerOf2OrZero(LHS, RHS, IsAnd, Builder, *this))
+  // (icmp ult/ule X, C1) & (icmp eq (and X, C2), C3) --> (icmp eq (and X, C2), C3)
+  // when the masked equality implies the range check.
+  if (Value *V = foldAndOfICmpRangeAndMaskedEq(LHS, RHS, IsAnd, IsLogical, Builder))
     return V;
+  if (Value *V = foldAndOfICmpRangeAndMaskedEq(RHS, LHS, IsAnd, IsLogical, Builder))
+    return V;
+
+  if (Value *V = foldIsPowerOf2OrZero(LHS, RHS, IsAnd, Builder, *this))
   if (Value *V = foldIsPowerOf2OrZero(RHS, LHS, IsAnd, Builder, *this))
     return V;

log.expect_optimized_program:
define i1 @merge_range_check_and(i8 %a) {
  %and = icmp eq i8 %a, 2
  ret i1 %and
}

define i1 @implied_select_icmp_eq_and_pow2(i32 %x) {
  %1 = and i32 %x, -32
  %2 = icmp eq i32 %1, 128
  ret i1 %2
}

define i1 @implied_range_check(i8 %a) {
  %1 = and i8 %a, -2
  %and = icmp eq i8 %1, 2
  ret i1 %and
}

log.current_optimized_program:
define i1 @implied_range_check(i8 %a) {
  %masked = and i8 %a, -2
  %cmp2 = icmp eq i8 %masked, 2
  ret i1 %cmp2
}

log.expect_optimized_program:
define i1 @merge_range_check_or(i8 %a) {
  %and = icmp ult i8 %a, 4
  ret i1 %and
}

define i1 @isFloat(i64 %0) {
  %2 = icmp ugt i64 %0, 562949953421311
  ret i1 %2
}
